package com.example.usage;

import com.auth0.auth0.Auth0Auth0Client;
import com.auth0.auth0.types.AuthenticatorAttestationResponse;
import com.auth0.auth0.types.AuthenticatorAttestationResponseData;
import com.auth0.auth0.types.VerifyAuthenticationMethodRequestContent;
import com.auth0.auth0.types.VerifyPasskeyAuthenticationMethod;

public class Example {
    public static void main(String[] args) {
        Auth0Auth0Client client = Auth0Auth0Client
            .builder()
            .token("<token>")
            .build();

        client.authenticationMethods().verify(
            "authentication_method_id",
            VerifyAuthenticationMethodRequestContent.of(
                VerifyPasskeyAuthenticationMethod
                    .builder()
                    .authSession("auth_session")
                    .authnResponse(
                        AuthenticatorAttestationResponse
                            .builder()
                            .id("id")
                            .rawId("rawId")
                            .response(
                                AuthenticatorAttestationResponseData
                                    .builder()
                                    .attestationObject("attestationObject")
                                    .clientDataJson("clientDataJSON")
                                    .build()
                            )
                            .type("public-key")
                            .build()
                    )
                    .build()
            )
        );
    }
}

